                  )}
                </div>
                <Toggle on={!!form.show_logo} onChange={v=>set('show_logo',v?1:0)} label="Show logo on printed bill" sub="Turn off to hide logo even if uploaded"/>
              </div>
            </div>
          )}

          {/* Options */}
          {tab === 'options' && (
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:20 }}>
