                      {PRESET_COLORS.map(c=>(
                        <div key={c} onClick={()=>set('primary_color',c)} style={{
                          width:32, height:32, borderRadius:9, background:c, cursor:'pointer',
                          border: form.primary_color===c?'2.5px solid var(--ink)':'2px solid transparent',
